query:
-- Total de ratings Moody's
SELECT COUNT(*) as total FROM moodys_ratings;

-- Breakdown por isEmissao
SELECT isEmissao, COUNT(*) as qtd FROM moodys_ratings GROUP BY isEmissao;

-- Ver exemplos de linhas com isEmissao = false (corporativos)
SELECT emissor, instrumento, rating, isEmissao, numeroEmissao
FROM moodys_ratings
WHERE isEmissao = false
LIMIT 10;

